import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TagResult {
  tags: string[];
  hashtags: string[];
  explanation: string;
}

export enum LoadingStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { TagResult } from "../types";

export const generateYouTubeSEO = async (keyword: string): Promise<TagResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `Act as a world-class YouTube SEO specialist. The user wants to generate high-performing, trending tags and hashtags for their video about: "${keyword}". 
  Provide a list of 20 high-volume tags, 10 trending hashtags, and a brief explanation of why these are good for ranking.
  Language context: If the keyword is in Bengali, provide a mix of Bengali and English tags.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          tags: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "List of 15-20 SEO tags for YouTube metadata."
          },
          hashtags: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "List of 10 trending hashtags starting with #."
          },
          explanation: {
            type: Type.STRING,
            description: "A short 1-2 sentence explanation of the SEO strategy used."
          }
        },
        required: ["tags", "hashtags", "explanation"]
      }
    }
  });

  const resultText = response.text;
  if (!resultText) {
    throw new Error("No response generated");
  }

  return JSON.parse(resultText) as TagResult;
};

import React, { useState } from 'react';

interface TagDisplayProps {
  title: string;
  items: string[];
  type: 'tags' | 'hashtags';
}

const TagDisplay: React.FC<TagDisplayProps> = ({ title, items, type }) => {
  const [copied, setCopied] = useState(false);

  const copyToClipboard = () => {
    const text = type === 'tags' ? items.join(', ') : items.join(' ');
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 transition-all hover:shadow-md">
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
          {title}
          <span className="bg-red-50 text-red-600 text-xs px-2 py-1 rounded-full font-medium">
            {items.length} Items
          </span>
        </h3>
        <button
          onClick={copyToClipboard}
          className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all ${
            copied 
              ? 'bg-green-500 text-white' 
              : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
          }`}
        >
          {copied ? 'Copied!' : 'Copy All'}
        </button>
      </div>
      <div className="flex flex-wrap gap-2">
        {items.map((item, idx) => (
          <span 
            key={idx}
            className={`px-3 py-1 rounded-lg text-sm transition-colors ${
              type === 'hashtags' 
                ? 'bg-blue-50 text-blue-700 border border-blue-100 font-medium' 
                : 'bg-slate-50 text-slate-700 border border-slate-200'
            }`}
          >
            {item}
          </span>
        ))}
      </div>
    </div>
  );
};

export default TagDisplay;

