  1. **Trending Tags (ট্যাগ)**: Provide a massive list of trending tags, search terms, and long-tail keywords. The total word count of these tags MUST be approximately 480 words. These will be used as a keyword bank for maximum SEO reach.
  2. **Video Description**: A high-quality, SEO-optimized video description of exactly 300 words. It should be engaging and include natural keyword integration.
  3. **Hashtags**: 10-15 trending hashtags.
  4. **Strategy**: A brief explanation of the ranking strategy.

  Language context: If the keyword is in Bengali, the content should be primarily in Bengali with relevant English SEO terms mixed in.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          tags: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "A very large list of tags totaling approximately 480 words."
          },
          hashtags: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "10-15 trending hashtags starting with #."
          },
          description: {
            type: Type.STRING,
            description: "A detailed 300-word SEO-friendly video description."
          },
          explanation: {
            type: Type.STRING,
            description: "A short explanation of the SEO strategy."
          }
        },
        required: ["tags", "hashtags", "description", "explanation"]
      }
    }
  });

  const resultText = response.text;
  if (!resultText) {
    throw new Error("No response generated");
  }

  return JSON.parse(resultText) as TagResult;
};

import React, { useState } from 'react';

interface TagDisplayProps {
  title: string;
  items: string[];
  type: 'tags' | 'hashtags';
}

const TagDisplay: React.FC<TagDisplayProps> = ({ title, items, type }) => {
  const [copied, setCopied] = useState(false);

  const copyToClipboard = () => {
    const text = type === 'tags' ? items.join(', ') : items.join(' ');
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 flex flex-col h-full transition-all hover:shadow-md">
      <div className="flex items-center justify-between mb-4 flex-shrink-0">
