export interface TagResult {
  tags: string[];
  hashtags: string[];
  description: string;
}

export enum LoadingStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { TagResult } from "../types";

export const generateYouTubeSEO = async (keyword: string): Promise<TagResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `Act as a world-class YouTube SEO specialist. The user wants to generate high-performing, trending content for a video about: "${keyword}". 

  Requirements:
  1. **Trending Tags (ট্যাগ)**: Provide a massive list of trending tags and long-tail keywords. The total word count of these tags MUST be at least 350 words (aim for 350-400 words).
  2. **Video Description**: A professional, SEO-optimized video description of exactly 300 words.
  3. **Hashtags**: 10-15 trending hashtags starting with #.

  Output MUST be in JSON format.
  Language context: If the keyword is in Bengali, provide the content primarily in Bengali with relevant English SEO terms mixed in. Do NOT include any explanation or strategy text.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          tags: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "A very large list of tags totaling 350+ words."
          },
          hashtags: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "10-15 trending hashtags."
          },
          description: {
            type: Type.STRING,
            description: "A detailed 300-word SEO description."
          }
        },
        required: ["tags", "hashtags", "description"]
      }
    }
  });

  const resultText = response.text;
  if (!resultText) {
    throw new Error("No response generated");
  }

  return JSON.parse(resultText) as TagResult;
};

