import { GoogleGenAI, Type } from "@google/genai";
import { TagResult } from "../types";

export const generateYouTubeSEO = async (keyword: string): Promise<TagResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `Act as a world-class YouTube SEO specialist. The user wants to generate high-performing, trending content for a video about: "${keyword}". 

  Requirements:
  1. **Trending Tags**: Provide exactly 20 high-performing, trending tags and long-tail keywords. 
  2. **Video Description**: A professional, SEO-optimized video description of exactly 300 words.
  3. **Hashtags**: 10-15 trending hashtags starting with #.

  CRITICAL: All generated content MUST be in English language only. 
  Output MUST be in JSON format. Do NOT include any explanation or strategy text.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          tags: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "Exactly 20 high-performing trending tags in English."
          },
          hashtags: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "10-15 trending hashtags in English."
          },
          description: {
            type: Type.STRING,
            description: "A detailed 300-word SEO description in English."
          }
        },
        required: ["tags", "hashtags", "description"]
      }
    }
  });

  const resultText = response.text;
  if (!resultText) {
    throw new Error("No response generated");
  }

  return JSON.parse(resultText) as TagResult;
};

